import{_ as o,o as r,c as e,ag as a}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"动态工作流","description":"","frontmatter":{},"headers":[],"relativePath":"features/workflows.md","filePath":"features/workflows.md"}'),s={name:"features/workflows.md"};function d(n,t,l,i,c,h){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="动态工作流" tabindex="-1">动态工作流 <a class="header-anchor" href="#动态工作流" aria-label="Permalink to &quot;动态工作流&quot;">​</a></h1><p>LoongCode 支持 <strong>Claude Code 动态工作流（Workflow）</strong>：你把一段工作流脚本放到约定目录，它就会出现在 <code>/</code> 命令面板里；在对话中触发后，LoongCode 把工作流的运行过程渲染成一张<strong>富进度卡片</strong>——按阶段、子智能体展示实时进度、用量与最终结果，还能逐个<strong>下钻</strong>查看子智能体的完整对话（v0.7.2 起）。</p><blockquote><p>相关基础：<a href="/docs/features/slash-commands.html">斜杠命令与文件面板</a>、<a href="/docs/features/subagents.html">子智能体</a></p></blockquote><div class="tip custom-block"><p class="custom-block-title">仅 Claude</p><p>动态工作流是 <strong>Claude Code</strong> 的能力，仅在使用 Claude CLI 的任务中可用；Codex 任务不提供此功能。</p></div><hr><h2 id="工作流从哪里来" tabindex="-1">工作流从哪里来 <a class="header-anchor" href="#工作流从哪里来" aria-label="Permalink to &quot;工作流从哪里来&quot;">​</a></h2><p>工作流是放在约定目录下的 <code>.js</code> 脚本文件，LoongCode 会自动扫描并把它们收进 <code>/</code> 命令面板：</p><table tabindex="0"><thead><tr><th>来源</th><th>存放位置</th><th>命令面板中的来源徽标</th></tr></thead><tbody><tr><td><strong>用户级</strong></td><td><code>~/.claude/workflows/*.js</code></td><td>user（蓝色）</td></tr><tr><td><strong>项目级</strong></td><td>当前工作区下 <code>.claude/workflows/*.js</code></td><td>project（绿色）</td></tr></tbody></table><ul><li>同名时<strong>项目级覆盖用户级</strong>。</li><li>工作流条目在命令面板中带玫红色 <strong>workflow</strong> 类型徽标，与普通命令、技能区分（见<a href="/docs/features/slash-commands.html#命令来源徽标">斜杠命令的来源/类型徽标</a>）。</li><li>新增或修改工作流脚本后，命令面板会<strong>自动感知变更</strong>并更新列表，无需重启应用。</li></ul><div class="tip custom-block"><p class="custom-block-title">工作流脚本由谁编写</p><p>工作流脚本本身遵循 Claude Code 的工作流约定（脚本里声明名称、描述与各阶段逻辑）。LoongCode 只负责<strong>发现、触发与可视化</strong>，不限制脚本内容。脚本的 <code>name</code> / <code>description</code> 会作为命令面板里的标题与说明展示。</p></div><hr><h2 id="触发工作流" tabindex="-1">触发工作流 <a class="header-anchor" href="#触发工作流" aria-label="Permalink to &quot;触发工作流&quot;">​</a></h2><p>与调用普通斜杠命令完全一致：</p><ol><li>在输入框输入 <code>/</code> 打开命令面板。</li><li>输入关键词筛选到目标工作流（带玫红 <strong>workflow</strong> 徽标）。</li><li>按 <strong>Enter</strong> 或点击选中，像发普通消息一样发送。</li></ol><p>发送后，对话区会出现一张<strong>工作流进度卡片</strong>，开始实时跟踪运行过程。</p><hr><h2 id="进度卡片" tabindex="-1">进度卡片 <a class="header-anchor" href="#进度卡片" aria-label="Permalink to &quot;进度卡片&quot;">​</a></h2><p>工作流运行时渲染为一张可折叠的富卡片，自上而下包含：</p><ul><li><strong>标题行</strong>：工作流名称 + 玫红 workflow 徽标 + 右侧<strong>整体状态</strong>（<code>⟳ 运行中</code> / <code>✓ 已完成</code> / <code>✗ 失败</code>）。点击标题行可<strong>整卡折叠 / 展开</strong>。</li><li><strong>阶段列表</strong>：工作流的各个阶段（Phase）按顺序排列，每个阶段前有一枚状态圆点，点击阶段行可<strong>折叠 / 展开该阶段下的子智能体</strong>。</li><li><strong>子智能体行</strong>：某阶段派生的子智能体（Agent）并列其下，显示标签、所用模型徽标，以及该子智能体的运行状态（<code>运行中</code> / <code>已完成</code> / <code>失败</code> / <code>排队中</code>）。</li><li><strong>底部用量条</strong>：本次运行的耗时、子智能体数量、消耗 tokens（千分位）。</li><li><strong>最终结果</strong>：运行结束后（非运行态）在卡片底部展示工作流返回的最终结果文本。</li></ul><h3 id="状态圆点颜色" tabindex="-1">状态圆点颜色 <a class="header-anchor" href="#状态圆点颜色" aria-label="Permalink to &quot;状态圆点颜色&quot;">​</a></h3><table tabindex="0"><thead><tr><th>圆点</th><th>含义</th></tr></thead><tbody><tr><td>灰</td><td>排队中 / 已派发待执行</td></tr><tr><td>黄（转动）</td><td>运行中</td></tr><tr><td>绿</td><td>已完成</td></tr><tr><td>红</td><td>失败 / 被取消</td></tr></tbody></table><p>阶段圆点按其下子智能体的整体进度推导；当整个工作流运行完成时，所有圆点统一显示为绿色。</p><h3 id="阶段自动折叠" tabindex="-1">阶段自动折叠 <a class="header-anchor" href="#阶段自动折叠" aria-label="Permalink to &quot;阶段自动折叠&quot;">​</a></h3><p>为了减少干扰，阶段默认遵循<strong>自动折叠规则</strong>：<strong>有子智能体正在运行的阶段自动展开</strong>，其余阶段自动收缩。你随时可以<strong>手动点击</strong>某个阶段行覆盖这一规则（手动选择优先于自动规则）。</p><hr><h2 id="下钻查看子智能体对话" tabindex="-1">下钻查看子智能体对话 <a class="header-anchor" href="#下钻查看子智能体对话" aria-label="Permalink to &quot;下钻查看子智能体对话&quot;">​</a></h2><p>工作流派生的每个子智能体都有自己的完整对话记录。在进度卡片上<strong>点击某个子智能体行</strong>，即可在其下方<strong>展开该子智能体的完整 transcript</strong>（用户消息、思考内容、助手回复、工具调用卡片等），与主对话的渲染一致。再次点击同一行收起。</p><ul><li>transcript 为<strong>懒加载</strong>：点开时才去读取，读到后缓存，避免一次性加载全部子智能体。</li><li><strong>排队中、尚未启动</strong>的子智能体没有对话记录，点击不会展开（无可下钻内容）。</li><li>子智能体运行<strong>完成后</strong>，其 transcript 会自动刷新为完整版本——避免出现「子智能体已显示完成，但下钻里最后一条工具仍停在运行中」的情况。</li></ul><hr><h2 id="关闭后重开-从磁盘还原" tabindex="-1">关闭后重开：从磁盘还原 <a class="header-anchor" href="#关闭后重开-从磁盘还原" aria-label="Permalink to &quot;关闭后重开：从磁盘还原&quot;">​</a></h2><p>工作流的运行记录会被持久化。关闭任务后重新打开，LoongCode 会<strong>从磁盘重建工作流卡片</strong>，还原：</p><ul><li>工作流名称、最终状态（已完成 / 失败）与最终结果；</li><li>各阶段与各子智能体的列表及其状态；</li><li>顶部用量（总 tokens、子智能体数量等）。</li></ul><p>还原出的卡片同样支持<strong>整卡折叠</strong>与<strong>子智能体下钻</strong>。还原态卡片不会再显示「运行中」——历史记录只呈现终态。</p><hr><h2 id="运行期间的保活" tabindex="-1">运行期间的保活 <a class="header-anchor" href="#运行期间的保活" aria-label="Permalink to &quot;运行期间的保活&quot;">​</a></h2><p>工作流通常会跨越<strong>多轮</strong>模型调用、并派生多个子智能体，整个过程可能比一次普通对话回合长。LoongCode 会在工作流<strong>仍在运行时保持事件订阅</strong>，确保后续阶段进度、子智能体状态与最终完成都能实时反映到卡片上，不会因为「触发那一轮已结束」而中断更新。</p><p>若过程中进程异常退出，未完成的工作流会被<strong>兜底标记为失败</strong>，卡片状态翻为 <code>✗ 失败</code>，不会一直停在「运行中」。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解动态工作流之后，可以继续探索如何让消息到点自动发送，前往<a href="/docs/features/scheduled-send.html">定时执行消息</a>继续学习。</p>',40)])])}const p=o(s,[["render",d]]);export{u as __pageData,p as default};
